import React, {
  useState,
  Suspense,
  lazy,
  useEffect,
  useMemo,
  useRef,
} from "react";
import SiteHeader from "main/SiteHeader";
import EducationSection from "main/Education";
import Section from "main/Section";
import {
  Box,
  Button,
  IconButton,
  Skeleton,
  Typography,
  useTheme,
  useMediaQuery,
} from "@mui/material";
import ArrowBackIcon from "@mui/icons-material/ArrowBack";
import {
  personalInfo,
  education,
  experience,
  projects,
  volunteering,
} from "content/site/siteData";
import { TechTagList } from "main/Components";
import { useContentMode } from "./hooks/useContentMode";
import { generateSlug, generateId } from "main/utils";

const DetailPane = lazy(() => import("main/DetailPane"));
const BlogView = lazy(() => import("main/BlogView"));
const ProjectBottomSheet = lazy(() => import("main/ProjectBottomSheet"));
const DESKTOP_PANE_HEIGHT = "calc(100vh - 3rem)";

const SECTION_LINKS = [
  { id: "section-about", label: "About" },
  { id: "section-education", label: "Education" },
  { id: "section-experience", label: "Experience" },
  { id: "section-leadership", label: "Leadership" },
  { id: "section-projects", label: "Projects" },
];

const SectionIndex = ({ onJump, activeSectionId }) => {
  return (
    <Box
      sx={{
        position: "sticky",
        top: 0,
        zIndex: 2,
        py: 1,
        mb: 1,
        backgroundColor: "background.paper",
      }}
    >
      <Box
        sx={{
          display: "flex",
          flexWrap: "nowrap",
          alignItems: "center",
          gap: 0.25,
          overflowX: "scroll",
        }}
      >
        {SECTION_LINKS.map((section) => (
          <Button
            key={section.id}
            size="small"
            variant="text"
            disableRipple
            onClick={() => onJump(section.id)}
            sx={{
              textTransform: "none",
              minWidth: 0,
              flexShrink: 0,
              px: 0.75,
              py: 0.35,
              borderRadius: "0.5rem",
              color:
                activeSectionId === section.id
                  ? "text.primary"
                  : "text.secondary",
              fontWeight: activeSectionId === section.id ? 700 : 600,
              whiteSpace: "nowrap",
              opacity: activeSectionId === section.id ? 1 : 0.82,
              "&:hover": {
                backgroundColor: "action.hover",
                opacity: 1,
              },
            }}
          >
            {section.label}
          </Button>
        ))}
      </Box>
    </Box >
  );
};

const DetailPaneLoading = ({ width = "70%" }) => {
  return (
    <Box sx={{ width, p: 4 }}>
      <Skeleton variant="text" width="30%" height={36} />
      <Skeleton variant="text" width="55%" height={28} />
      <Skeleton variant="rounded" width="100%" height={180} sx={{ my: 2 }} />
      <Skeleton variant="text" width="96%" height={26} />
      <Skeleton variant="text" width="92%" height={26} />
      <Skeleton variant="text" width="88%" height={26} />
    </Box>
  );
};

const HomePage = () => {
  const theme = useTheme();
  const matches = useMediaQuery(theme.breakpoints.up("md"));

  const {
    isArticleMode,
    isStandaloneProject,
    selectedContent,
    selectedId,
    selectedProject,
    parentItem,
    selectedItem,
    handleSelect,
    getArticleUrl,
    navigate,
  } = useContentMode();

  const [bottomSheetProject, setBottomSheetProject] = useState(null);
  const [activeSectionId, setActiveSectionId] = useState(SECTION_LINKS[0].id);
  const leftPaneRef = useRef(null);

  const randomProjectOptions = useMemo(() => {
    const nested = [...experience, ...volunteering].flatMap((item) =>
      (item.projects || []).map((proj) => ({
        id: generateId({
          ...proj,
          title: proj.projectName,
          organization: item.organization,
        }),
        title: proj.projectName,
      }))
    );
    const standalone = projects.map((project) => ({
      id: generateId(project),
      title: project.title,
    }));
    return [...nested, ...standalone];
  }, []);

  const [randomSuggestion, setRandomSuggestion] = useState(null);

  useEffect(() => {
    if (matches && !isArticleMode && !selectedId && randomProjectOptions.length) {
      const next =
        randomProjectOptions[
        Math.floor(Math.random() * randomProjectOptions.length)
        ];
      setRandomSuggestion(next);
    }
  }, [matches, isArticleMode, selectedId, randomProjectOptions]);

  useEffect(() => {
    if (!matches || isArticleMode || !leftPaneRef.current) return;

    const root = leftPaneRef.current;
    setActiveSectionId("section-about");

    const sections = SECTION_LINKS.map((section) => {
      const element = document.getElementById(section.id);
      return element ? { id: section.id, element } : null;
    }).filter(Boolean);
    if (!sections.length) return;

    const updateActiveSection = () => {
      const anchor = root.scrollTop + 100;
      let currentId = sections[0].id;

      for (const section of sections) {
        if (section.element.offsetTop <= anchor) {
          currentId = section.id;
        } else {
          break;
        }
      }

      setActiveSectionId(currentId);
    };

    updateActiveSection();
    root.addEventListener("scroll", updateActiveSection, { passive: true });
    window.addEventListener("resize", updateActiveSection);

    return () => {
      root.removeEventListener("scroll", updateActiveSection);
      window.removeEventListener("resize", updateActiveSection);
    };
  }, [matches, isArticleMode]);

  const handleMobileStandaloneSelect = (id) => {
    const found = projects.find((p) => generateId(p) === id);
    if (found) setBottomSheetProject({ item: found, parent: null });
  };

  const handleClose = () => {
    if (isArticleMode) {
      navigate("/", {
        viewTransition: true,
        state: { restoreProjectId: selectedId },
      });
    } else {
      handleSelect(null);
    }
  };

  const handleExpand = () => {
    if (!selectedProject) return;
    const url = parentItem
      ? getArticleUrl(selectedProject.projectName, parentItem)
      : `/projects/${generateSlug(selectedProject.projectName)}`;
    navigate(url, { viewTransition: true });
  };

  const handleMobileProjectSelect = (id, content, proj, parent) => {
    if (!proj) return;
    setBottomSheetProject({ item: proj, parent });
  };

  const aboutItem = { title: "Leo Liu" };

  const detailPaneContent =
    selectedId === "leo-liu" ? (
      <SiteHeader personalInfo={personalInfo} variant="detailPane" />
    ) : (
      selectedContent
    );

  const handleJumpToSection = (sectionId) => {
    setActiveSectionId(sectionId);
    const section = document.getElementById(sectionId);
    if (section) {
      section.scrollIntoView({ behavior: "smooth", block: "start" });
    }
  };

  return (
    <>
      <Box sx={{ textAlign: "start" }}>
        {!isArticleMode && !matches && <SiteHeader personalInfo={personalInfo} />}
        {matches ? (
          <Box
            sx={{
              display: "flex",
              alignItems: "flex-start",
              gap: 0,
              height: isArticleMode ? "auto" : DESKTOP_PANE_HEIGHT,
              overflow: isArticleMode ? "visible" : "hidden",
              borderRadius: isArticleMode ? 0 : "1rem",
              border: (theme) =>
                !isArticleMode ? `1px solid ${theme.palette.divider}` : "none",
              bgcolor: isArticleMode ? "transparent" : "background.paper",
              transition: theme.transitions.create(["gap", "height"], {
                duration: theme.transitions.duration.standard,
                easing: theme.transitions.easing.easeInOut,
              }),
            }}
          >
            <Box
              sx={{
                display: isArticleMode ? "none" : "block",
                width: "30%",
                height: isArticleMode ? "auto" : DESKTOP_PANE_HEIGHT,
                borderRight: (theme) =>
                  !isArticleMode ? `1px solid ${theme.palette.divider}` : "none",
                transition: theme.transitions.create("width", {
                  duration: theme.transitions.duration.complex,
                  easing: theme.transitions.easing.easeInOut,
                }),
              }}
            >
              <Box
                ref={leftPaneRef}
                sx={{
                  p: 3,
                  pt: 0,
                  height: "100%",
                  overflowY: "auto",
                  overflowX: "hidden",
                  "& .MuiTypography-h3": {
                    mt: 2,
                  },
                }}
              >
                <SectionIndex
                  onJump={handleJumpToSection}
                  activeSectionId={activeSectionId}
                />
                <Section
                  sectionTitle="About Me"
                  items={[aboutItem]}
                  selectedId={selectedId}
                  onSelect={handleSelect}
                  sectionId="section-about"
                />
                <EducationSection
                  educationData={education}
                  selectedId={selectedId}
                  onSelect={handleSelect}
                  sectionId="section-education"
                />
                <Section
                  sectionTitle="Experience"
                  items={experience}
                  selectedId={selectedId}
                  onSelect={handleSelect}
                  sectionId="section-experience"
                />
                <Section
                  sectionTitle="Leadership"
                  items={volunteering}
                  selectedId={selectedId}
                  onSelect={handleSelect}
                  sectionId="section-leadership"
                />
                <Section
                  sectionTitle="Projects"
                  items={projects}
                  selectedId={selectedId}
                  onSelect={handleSelect}
                  sectionId="section-projects"
                />
              </Box>
            </Box>

            <Suspense fallback={<DetailPaneLoading />}>
              <DetailPane
                isBlogMode={isArticleMode}
                selectedContent={detailPaneContent}
                selectedProject={selectedProject}
                parentItem={parentItem}
                selectedItem={selectedItem}
                selectedId={selectedId}
                onClose={handleClose}
                onExpand={handleExpand}
                navigate={navigate}
                getBlogUrl={getArticleUrl}
                desktopHeight={DESKTOP_PANE_HEIGHT}
                emptyState={
                  !isArticleMode ? (
                    <>
                      <Typography
                        sx={{
                          color: "text.primary",
                          textAlign: "center",
                          fontWeight: 700,
                        }}
                      >
                        👈 Select an experience, leadership role, or project on the
                        left to view details
                      </Typography>
                      {randomSuggestion && (
                        <Box
                          sx={{
                            display: "flex",
                            flexDirection: "column",
                            alignItems: "center",
                            gap: 1,
                          }}
                        >
                          <Typography
                            variant="body2"
                            color="text.secondary"
                            textAlign="center"
                          >
                            Feeling lucky? Check out {randomSuggestion.title}
                          </Typography>
                          <Button
                            variant="outlined"
                            onClick={() => handleSelect(randomSuggestion.id)}
                            disableRipple
                            sx={{ textTransform: "none", borderRadius: "999px" }}
                          >
                            Show random project
                          </Button>
                        </Box>
                      )}
                      <Box>
                        <Box
                          sx={{
                            width: "460px",
                            height: "260px",
                            backgroundImage: "url(/photos/optimized/IMG_0206.jpg)",
                            backgroundSize: "cover",
                            backgroundPosition: "center",
                            borderRadius: "1rem",
                            overflow: "hidden",
                          }}
                        />
                        <Typography
                          variant="body1"
                          paragraph
                          color="text.secondary"
                          textAlign="end"
                          sx={{ mt: "0.5rem" }}
                        >
                          Kelowna, BC
                        </Typography>
                      </Box>
                    </>
                  ) : null
                }
              />
            </Suspense>
          </Box>
        ) : isArticleMode && selectedContent ? (
          <Box style={{ viewTransitionName: "project-modal" }}>
            <Box sx={{ position: "relative", pt: 1 }}>
              <IconButton onClick={handleClose} sx={{ mb: 1, pl: 0 }} size="small">
                <ArrowBackIcon fontSize="small" />
              </IconButton>
              {isStandaloneProject ? (
                <Box sx={{ mb: 3 }}>
                  <Typography variant="h4" fontWeight="bold" gutterBottom>
                    {projects.find((p) => generateId(p) === selectedId)?.title}
                  </Typography>
                  {(() => {
                    const project = projects.find((p) => generateId(p) === selectedId);
                    return (
                      <>
                        {project?.caption && (
                          <Typography variant="subtitle1" color="text.secondary">
                            {project.caption}
                          </Typography>
                        )}
                        {project?.technologies && (
                          <Typography variant="caption" color="text.disabled">
                            {project.technologies}
                          </Typography>
                        )}
                        <TechTagList
                          technologies={project?.tags || project?.technologies}
                          sx={{ mt: 1 }}
                        />
                      </>
                    );
                  })()}
                </Box>
              ) : (
                <Suspense fallback={<DetailPaneLoading width="100%" />}>
                  <BlogView
                    selectedProject={selectedProject}
                    parentItem={parentItem}
                    selectedId={selectedId}
                    navigate={navigate}
                    getBlogUrl={getArticleUrl}
                    variant="mobile"
                  />
                </Suspense>
              )}
              {selectedContent}
            </Box>
          </Box>
        ) : (
          <>
            <EducationSection educationData={education} sectionId="section-education" />
            <Section
              sectionTitle="Experience"
              items={experience}
              onSelect={handleMobileProjectSelect}
              showOverviewInFolder
              sectionId="section-experience"
            />
            <Section
              sectionTitle="Leadership"
              items={volunteering}
              onSelect={handleMobileProjectSelect}
              showOverviewInFolder
              sectionId="section-leadership"
            />
            <Section
              sectionTitle="Projects"
              items={projects}
              onSelect={handleMobileStandaloneSelect}
              sectionId="section-projects"
            />
          </>
        )}
      </Box>
      <Suspense fallback={null}>
        <ProjectBottomSheet
          project={bottomSheetProject?.item}
          open={Boolean(bottomSheetProject)}
          onClose={() => setBottomSheetProject(null)}
          onExpand={() => {
            const { item, parent } = bottomSheetProject;
            const url = item.projectName
              ? getArticleUrl(item.projectName, parent)
              : `/projects/${generateSlug(item.title)}`;
            navigate(url, { viewTransition: true });
            setBottomSheetProject(null);
          }}
        />
      </Suspense>
    </>
  );
};

export default HomePage;
